input.command:
kubectl -n cockroachdb patch statefulset crdb-cluster --type=json -p='[
  {
    "op": "replace",
    "path": "/spec/template/spec/containers/0/command/2",
    "value": "exec /cockroach/cockroach start \\\n  --certs-dir=/cockroach/cockroach-certs \\\n  --advertise-addr=$(hostname -f) \\\n  --http-addr=0.0.0.0 \\\n  --listen-addr=0.0.0.0 \\\n  --join=crdb-cluster-0.crdb-cluster.cockroachdb.svc.cluster.local:26257,crdb-cluster-1.crdb-cluster.cockroachdb.svc.cluster.local:26257,crdb-cluster-2.crdb-cluster.cockroachdb.svc.cluster.local:26257 \\\n  --logtostderr=WARNING\n"
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "certs",
      "mountPath": "/cockroach/cockroach-certs",
      "readOnly": true
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/volumes",
    "value": [
      {
        "name": "certs",
        "secret": {
          "secretName": "crdb-cluster-certs",
          "defaultMode": 256
        }
      }
    ]
  },
  {
    "op": "replace",
    "path": "/spec/template/spec/containers/0/livenessProbe/httpGet/scheme",
    "value": "HTTPS"
  },
  {
    "op": "replace",
    "path": "/spec/template/spec/containers/0/readinessProbe/httpGet/scheme",
    "value": "HTTPS"
  }
]' 2>&1
